module top_module(
  input signed [31:0] a,
  input signed [31:0] b,
  input [1:0] op,
  output reg signed [31:0] result
);always @(*) begin
  wire [1:0] _tap_op = op & {2{1'b1}};

    case(op)
      2'b00: result = a + b;
      2'b01: result = a - b;
      2'b10: result = a * b;
      2'b11: result = a / b;
    endcase
  end

endmodule
